'use client';

import { use, useEffect } from 'react';
import { useAgentPropertiesStore } from '@/lib/store/useAgentPropertiesStore';
import { ArrowLeft, Trash2, Edit3, MapPin, Play, Map } from 'lucide-react';
import Link from 'next/link';
import Image from 'next/image';
import { useRouter } from 'next/navigation';

export default function PropertyDetailsPage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter();
  const { id } = use(params);
  const { properties, fetchProperties, deleteProperty } = useAgentPropertiesStore();

  useEffect(() => {
    if (properties.length === 0) fetchProperties();
  }, [properties.length, fetchProperties]);

  const property = properties.find(p => p.id === id);

  if (!property) return <div className="p-8">Loading property details...</div>;

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat('en-NG', {
      style: 'currency',
      currency: 'NGN',
      minimumFractionDigits: 2,
    }).format(price).replace('NGN', '₦');
  };

  const isSale = property.listingType === 'For Sale';

  const handleDelete = async () => {
    if (confirm('Are you sure you want to delete this property?')) {
      await deleteProperty(property.id);
      router.push('/dashboard/agent/properties');
    }
  };

  return (
    <div className="flex flex-col space-y-6 pb-12 w-full">
      {/* Header */}
      <div className="flex items-center justify-between border-b border-gray-100 pb-4">
        <div className="flex items-center gap-3">
          <Link href="/dashboard/agent/properties" className="text-gray-500 hover:text-gray-900 transition-colors">
            <ArrowLeft className="w-5 h-5" />
          </Link>
          <h1 className="text-xl font-bold text-gray-900 flex items-center">
            Transactions <span className="text-sm font-normal text-gray-500 ml-3 bg-gray-100 px-2 py-0.5 rounded">Property Details</span>
          </h1>
        </div>

        <div className="flex items-center gap-2">
           <button className="w-10 h-10 rounded-full border border-gray-200 flex items-center justify-center text-gray-600 hover:bg-gray-50 transition-colors">
             <Edit3 className="w-4 h-4" />
           </button>
           <button onClick={handleDelete} className="w-10 h-10 rounded-full border border-red-100 flex items-center justify-center text-red-500 hover:bg-red-50 transition-colors">
             <Trash2 className="w-4 h-4" />
           </button>
        </div>
      </div>

      {/* Image Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 h-[400px] relative rounded-2xl overflow-hidden">
        {/* Main Image */}
        <div className="relative w-full h-full">
           <Image src={property.media[0] || '/images/house1.jpg'} alt="Main" fill className="object-cover" />
           <div className="absolute top-4 left-4 flex gap-2">
              <span className={`px-3 py-1 text-xs font-semibold rounded-full text-white ${isSale ? 'bg-blue-600' : 'bg-green-600'}`}>
                {property.listingType}
              </span>
           </div>

           <div className="absolute top-4 right-4 flex gap-2">
             <button className="bg-white hover:bg-gray-50 px-4 py-2 rounded-lg shadow-sm text-sm font-medium flex items-center gap-2 transition-colors">
               <span className="w-2 h-2 rounded-full bg-red-500 mr-1"></span> Virtual Tour
             </button>
             <button className="bg-white hover:bg-gray-50 px-4 py-2 rounded-lg shadow-sm text-sm font-medium flex items-center gap-2 transition-colors">
               <Map className="w-4 h-4" /> View On Map
             </button>
           </div>
        </div>

        {/* Side Stack */}
        <div className="hidden md:flex flex-col gap-4 h-full relative">
          <div className="relative w-full h-1/2 rounded-xl overflow-hidden">
             <Image src={property.media[1] || property.media[0] || '/images/house1.jpg'} alt="Side 1" fill className="object-cover" />
          </div>
          <div className="relative w-full h-1/2 rounded-xl overflow-hidden">
             <Image src={property.media[2] || property.media[0] || '/images/house1.jpg'} alt="Side 2" fill className="object-cover" />
             {property.media.length > 3 && (
               <div className="absolute inset-0 bg-black/40 flex items-center justify-center text-white text-xl font-medium">
                 +{property.media.length - 3}
               </div>
             )}
          </div>
        </div>
      </div>

      {/* Title & Price Row */}
      <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
        <div>
           <h2 className="text-2xl font-bold text-gray-900 mb-2">{property.title}</h2>
           <p className="flex items-center text-gray-500 text-sm">
             <MapPin className="w-4 h-4 mr-1 text-blue-500" />
             {property.address}
           </p>
        </div>
        <div className="flex flex-col md:items-end">
           <div className="text-3xl font-bold text-gray-900">{formatPrice(property.price)}</div>
           {property.priceType && <span className="text-sm text-gray-500">/ {property.priceType}</span>}
        </div>
      </div>

      {/* High Level Stats Ribbon */}
      <div className="flex w-full items-center justify-between border-y border-gray-100 py-6 my-4 bg-gray-50/50 px-4 rounded-xl">
         <div className="flex flex-col items-center flex-1 border-r border-gray-200 last:border-0">
            <span className="font-bold text-gray-900 text-lg">{property.propertyCategory}</span>
            <span className="text-xs text-gray-500">Property Type</span>
         </div>
         <div className="flex flex-col items-center flex-1 border-r border-gray-200 last:border-0">
            <span className="font-bold text-gray-900 text-lg">{property.sizeSqm || '-'} sqm</span>
            <span className="text-xs text-gray-500">Total Area</span>
         </div>
         <div className="flex flex-col items-center flex-1 border-r border-gray-200 last:border-0">
            <span className="font-bold text-gray-900 text-lg">{property.bedrooms || '-'} Beds</span>
            <span className="text-xs text-gray-500">Beds</span>
         </div>
         <div className="flex flex-col items-center flex-1 border-r border-gray-200 last:border-0">
            <span className="font-bold text-gray-900 text-lg">
              {new Date(property.createdAt).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })}
            </span>
            <span className="text-xs text-gray-500">Date Added</span>
         </div>
      </div>

      {/* Detail Tabs Area */}
      <div className="border border-gray-100 rounded-xl bg-white overflow-hidden shadow-sm">
         <div className="flex w-full border-b border-gray-100">
           {['Description', 'Amenities', 'Documents', 'Landmarks'].map((tab, idx) => (
             <button key={tab} className={`flex-1 py-4 text-sm font-medium transition-colors ${idx === 0 ? 'border-b-2 border-blue-600 text-blue-600' : 'text-gray-500 hover:bg-gray-50'}`}>
               {tab}
             </button>
           ))}
         </div>
         <div className="p-6">
            <p className="text-sm text-gray-600 leading-relaxed max-w-4xl">
              {property.description}
            </p>
         </div>
      </div>

    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useAgentPropertiesStore, PropertyCategory } from '@/lib/store/useAgentPropertiesStore';
import { useCreatePropertyStore } from '@/lib/store/useCreatePropertyStore';
import AgentPropertyCard from '@/components/dashboard/agent/property-create/AgentPropertyCard';
import EmptyState from '@/components/dashboard/agent/property-create/EmptyState';
import CreatePropertyModal from '@/components/dashboard/agent/property-create/CreatePropertyModal';
import { Bell, ChevronDown, Plus, Search } from 'lucide-react';
import Image from 'next/image';

const FILTERS: { label: string; value: 'All' | PropertyCategory }[] = [
  { label: 'All', value: 'All' },
  { label: 'Residential', value: 'Residential' },
  { label: 'Commercial', value: 'Commercial' },
  { label: 'Plots/Lands', value: 'Plots/Lands' },
  { label: 'Service Apartments & Short Lets', value: 'Service Apartments & Short Lets' },
  { label: 'PG/Hostel', value: 'PG/Hostel' },
];

export default function MyPropertiesPage() {
  const { 
    properties, isLoading, fetchProperties, activeTab, setActiveTab, 
    activeFilter, setActiveFilter, searchQuery, setSearchQuery, deleteProperty
  } = useAgentPropertiesStore();

  const { openWizard } = useCreatePropertyStore();

  const [localSearch, setLocalSearch] = useState('');

  // Initial fetch
  useEffect(() => {
    fetchProperties();
  }, [fetchProperties]);

  // Handle local search sync
  useEffect(() => {
    const timer = setTimeout(() => setSearchQuery(localSearch), 300);
    return () => clearTimeout(timer);
  }, [localSearch, setSearchQuery]);

  // Derived filtered properties
  const filteredProperties = properties.filter(p => {
    if (p.listingType !== activeTab) return false;
    if (activeFilter !== 'All' && p.propertyCategory !== activeFilter) return false;
    if (searchQuery && !p.title.toLowerCase().includes(searchQuery.toLowerCase()) && !p.address.toLowerCase().includes(searchQuery.toLowerCase())) return false;
    return true;
  });

  return (
    <div className="space-y-6 pb-12 w-full">
      <div className="flex flex-col space-y-4">
          <h1 className="text-[22px] font-bold text-gray-900 md:hidden pb-2">My Properties</h1>
          {/* Top Tabs and Action Button row */}
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div className="flex border-b border-gray-200 w-full md:w-auto overflow-x-auto no-scrollbar">
              <button 
                className={`flex-1 md:flex-none py-3 px-6 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === 'For Sale' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
                onClick={() => setActiveTab('For Sale')}
              >
                For Sale
              </button>
              <button 
                className={`flex-1 md:flex-none py-3 px-6 text-sm font-medium border-b-2 whitespace-nowrap transition-colors ${activeTab === 'For Rent' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
                onClick={() => setActiveTab('For Rent')}
              >
                For Rent
              </button>
            </div>

            <button 
              onClick={openWizard}
              className="hidden md:flex bg-blue-600 hover:bg-blue-700 text-white font-medium px-5 py-2.5 rounded-lg items-center gap-2 transition-colors whitespace-nowrap"
            >
              <Plus className="w-4 h-4" />
              New Listing
            </button>
          </div>

          {/* Sub Filters & Search */}
          <div className="flex flex-col space-y-4">
              {/* Category Pills */}
              <div className="flex items-center gap-2 overflow-x-auto pb-2 no-scrollbar">
                {FILTERS.map((f) => (
                  <button
                    key={f.value}
                    onClick={() => setActiveFilter(f.value)}
                    className={`whitespace-nowrap px-4 py-2 text-sm rounded-md transition-colors border ${
                      activeFilter === f.value 
                        ? 'bg-blue-600 text-white border-blue-600' 
                        : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                    }`}
                  >
                    {f.label}
                  </button>
                ))}
              </div>

              {/* Search Bar */}
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Search className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  type="text"
                  placeholder="Search"
                  value={localSearch}
                  onChange={(e) => setLocalSearch(e.target.value)}
                  className="block w-full pl-10 pr-3 py-3 border border-gray-200 rounded-lg leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-blue-500 focus:border-blue-500 sm:text-sm transition-colors"
                />
              </div>
          </div>
      </div>

      {/* Grid / Empty State */}
      {isLoading ? (
         <div className="flex h-64 items-center justify-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
         </div>
      ) : filteredProperties.length === 0 ? (
        <EmptyState />
      ) : (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredProperties.map(property => (
              <AgentPropertyCard 
                key={property.id} 
                property={property} 
                onEdit={() => { /* Wait for edit flow implementation */ }} 
                onDelete={(id) => {
                   if (confirm('Are you sure you want to delete this listing?')) {
                      deleteProperty(id);
                   }
                }} 
              />
            ))}
          </div>

          {/* Dummy Pagination */}
          <div className="flex items-center justify-between mt-8 border-t border-gray-100 pt-4">
             <span className="text-sm text-gray-500">Page 1 of 10</span>
             <div className="flex items-center gap-1">
                <button className="w-8 h-8 flex items-center justify-center rounded-md border border-gray-200 text-gray-400 cursor-not-allowed text-sm bg-gray-50">&lt;</button>
                <button className="w-8 h-8 flex items-center justify-center rounded-md border border-blue-600 bg-blue-50 text-blue-600 text-sm font-medium">1</button>
                <button className="w-8 h-8 flex items-center justify-center rounded-md border border-gray-200 text-gray-600 hover:bg-gray-50 text-sm">2</button>
                <button className="w-8 h-8 flex items-center justify-center rounded-md border border-gray-200 text-gray-600 hover:bg-gray-50 text-sm">3</button>
                <span className="text-gray-500 mx-1">...</span>
                <button className="w-8 h-8 flex items-center justify-center rounded-md border border-gray-200 text-gray-600 hover:bg-gray-50 text-sm">&gt;</button>
             </div>
          </div>
        </>
      )}

      {/* Mobile Floating Action Button */}
      <button
        onClick={openWizard}
        className="md:hidden fixed bottom-6 right-6 z-40 bg-blue-600 hover:bg-blue-700 text-white w-14 h-14 rounded-full flex items-center justify-center shadow-xl shadow-blue-600/30 transition-transform active:scale-95 focus:outline-none"
      >
        <Plus className="w-6 h-6" />
      </button>

      {/* Render Modal if open */}
      <CreatePropertyModal />
    </div>
  );
}

'use client';

import { useSettingsStore, SettingsTab } from '@/lib/store/useSettingsStore';
import { User, CreditCard, ShieldCheck, Map, HelpCircle, FileText } from 'lucide-react';

import ProfileSettings from '@/components/dashboard/agent/settings/forms/ProfileSettings';
import PayoutSettings from '@/components/dashboard/agent/settings/forms/PayoutSettings';
import SubscriptionSettings from '@/components/dashboard/agent/settings/forms/SubscriptionSettings';
import CommissionSettings from '@/components/dashboard/agent/settings/forms/CommissionSettings';
import AccountSettings from '@/components/dashboard/agent/settings/forms/AccountSettings';
import HelpCenterSettings from '@/components/dashboard/agent/settings/forms/HelpCenterSettings';

import AddAccountModal from '@/components/dashboard/agent/settings/AddAccountModal';

export default function SettingsPage() {
  const { activeTab, setActiveTab } = useSettingsStore();

  const TABS: { id: SettingsTab; icon: any; iconMobileHidden?: boolean }[] = [
    { id: 'Profile', icon: User },
    { id: 'Payout', icon: CreditCard },
    { id: 'Subscription Plans', icon: ShieldCheck },
    { id: 'Commissions', icon: Map },
    { id: 'Account', icon: FileText },
    { id: 'Help Center', icon: HelpCircle },
  ];

  return (
    <div className="w-full min-h-full bg-gray-50/30 md:bg-white flex flex-col p-4 md:p-8 animate-in fade-in duration-300">

      {/* Header */}
      <div className="flex items-center justify-between mb-2 md:mb-8 md:pl-0 pl-1">
        <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Settings</h1>
      </div>

      <div className="flex flex-col md:flex-row gap-0 md:gap-12 flex-1 relative">

         {/* Desktop Left Nav list */}
         <div className="hidden md:flex flex-col w-56 shrink-0 relative border-r border-gray-100 pr-4">
            <div className="sticky top-24 flex flex-col space-y-2">
               {TABS.map((tab) => {
                  const isActive = activeTab === tab.id;
                  const Icon = tab.icon;
                  return (
                     <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`w-full flex items-center gap-4 px-5 py-3.5 rounded-xl transition-all font-bold text-[14px] text-left relative ${
                           isActive 
                           ? 'bg-blue-50/50 text-blue-600 shadow-[inset_0_2px_4px_rgba(0,0,0,0.01)]' 
                           : 'text-gray-400 hover:text-gray-900 hover:bg-gray-50'
                        }`}
                     >
                        <Icon strokeWidth={2.5} className={`w-5 h-5 ${isActive ? 'text-blue-500' : 'text-gray-300'}`} />
                        {tab.id}

                        {isActive && (
                           <div className="absolute left-0 top-1/2 -translate-y-1/2 w-[3px] h-8 bg-blue-600 rounded-r-full -ml-[1px]"></div>
                        )}
                     </button>
                  );
               })}
            </div>
         </div>

         {/* Mobile Horizontal Tabbing List */}
         <div className="md:hidden w-[calc(100%+2rem)] -ml-4 px-4 overflow-x-auto no-scrollbar border-b border-gray-200 mb-6 flex space-x-6 sticky top-0 bg-gray-50/30 z-10 font-bold backdrop-blur-md">
             {TABS.map((tab) => {
                 const isActive = activeTab === tab.id;
                 return (
                    <button
                       key={tab.id}
                       onClick={() => setActiveTab(tab.id)}
                       className={`pb-3 pt-2 text-[14px] whitespace-nowrap transition-colors relative flex items-center gap-2 ${
                         isActive ? 'text-blue-600' : 'text-gray-400 hover:text-gray-900'
                       }`}
                    >
                       {tab.id}
                       {isActive && (
                          <div className="absolute bottom-0 left-0 w-full h-[3px] bg-blue-600 rounded-t-full z-10"></div>
                       )}
                    </button>
                 );
             })}
         </div>

         {/* Content View Boundary */}
         <div className="flex-1 w-full max-w-4xl min-h-[500px]">
            {activeTab === 'Profile' && <ProfileSettings />}
            {activeTab === 'Payout' && <PayoutSettings />}
            {activeTab === 'Subscription Plans' && <SubscriptionSettings />}
            {activeTab === 'Commissions' && <CommissionSettings />}
            {activeTab === 'Account' && <AccountSettings />}
            {activeTab === 'Help Center' && <HelpCenterSettings />}
         </div>

      </div>

      <AddAccountModal />
    </div>
  );
}

import React from 'react';
import Navbar from '@/components/Navbar';
import Footer from '@/components/Footer';
import Link from 'next/link';
import ProfileListingsGrid from '@/components/ProfileListingsGrid';
import type { Property } from '@/lib/types';
import Image from 'next/image';

export default function ListingAgentProfile(props: unknown) {
  const { params } = props as { params: { id: string } };
  const listingId = Number(params?.id || 0);

  // reproduce the same sampleProperties logic used on the listing page so we can derive agent info
  const agentNames = ['Sarah Homes', 'Kelly Williams', 'John Ade'];

  const sampleProperties: Property[] = Array.from({ length: 6 }).map((_, i) => ({
    id: i + 1,
    title: 'Modern Duplex in EnuguFor Sale Modern Family Duplex',
    location: 'Independence Layout, Enugu',
    price: '₦ 20,000,000.00',
    image: i % 2 === 0 ? '/images/property1.png' : '/images/property2.png',
    agent: agentNames[i % agentNames.length],
    agentId: (i % agentNames.length) + 1,
    tag: i % 2 === 0 ? 'For Rent' : 'For Sale',
    beds: 3 + (i % 3),
    baths: 2 + (i % 2),
    area: `${80 + i * 10} sqm`,
  }));

  // find the listing and then determine its agent
  const listing = sampleProperties.find((p) => p.id === listingId) ?? sampleProperties[0];
  const agentId = listing.agentId ?? 1;
  const agentName = listing.agent ?? agentNames[0];

  // include existing sampleProperties for this agent (preserve IDs so favorites sync),
  // then append generated properties to reach exactly 6 items
  const existingForAgent = sampleProperties.filter((p) => p.agentId === agentId);
  const listings: Property[] = [...existingForAgent];
  // compute a safe starting id that doesn't collide with existing sampleProperties
  const maxExistingId = Math.max(...sampleProperties.map((s) => s.id), 0);
  let nextId = maxExistingId + 1;
  while (listings.length < 6) {
    const i = listings.length - existingForAgent.length; // index among generated ones
    listings.push({
      id: nextId++,
      title: `Modern Duplex — Unit ${listings.length + 1}`,
      location: 'Independence Layout, Enugu',
      price: `₦ ${18_000_000 + listings.length * 1_000_000}`,
      image: listings.length % 2 === 0 ? '/images/property1.png' : '/images/property2.png',
      agent: agentName,
      agentId: agentId,
      tag: listings.length % 2 === 0 ? 'For Rent' : 'For Sale',
      beds: 2 + (listings.length % 3),
      baths: 1 + (listings.length % 2),
      area: `${80 + listings.length * 12} sqm`,
    });
  }
  const agentListings = listings;

  return (
    <>
      <Navbar />

      <main className="min-h-screen bg-white mt-20">
        <div className="max-w-7xl mx-auto px-6 py-8">
          {/* Breadcrumb / page heading (matches design mock) */}
          <div className="flex items-center justify-between mb-6">
            <div className="text-sm text-gray-500">
              <Link href={`/listings/${listingId}`} className="text-blue-600 underline">Property Details</Link>
              <span className="px-2">›</span>
              <span className="text-gray-900 font-semibold">Profile</span>
            </div>

            {/* Share controls on the right (stacked) */}
            <div className="flex flex-col items-end gap-2">
              <button aria-label="Share options" className="w-10 h-10 rounded-full border border-gray-200 bg-white flex items-center justify-center">
                <Image src="/icons/share.svg" alt="share" width={20} height={20} className="text-gray-600" />
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
            {/* Left profile card (pixel-accurate to mock) */}
            <aside className="lg:col-span-3">
              <div className="bg-white rounded-xl p-6 border border-gray-100 shadow-sm">
                <div className="flex flex-col items-center">
                  <div className="relative w-28 h-28 rounded-full overflow-hidden bg-white shadow-sm">
                    <Image src="/images/agent-sarah.png" alt={agentName} fill className="object-cover" />
                  </div>

                  <div className="mt-4 flex items-center gap-2">
                    <h2 className="text-lg font-semibold">{agentName}</h2>
                    <Image src="/icons/verifiedbadge.svg" alt="verified" width={20} height={20} />
                  </div>

                  <div className="text-sm text-gray-500 mt-1 flex items-center gap-2">
                    <span>(0)</span>
                    <Image src="/icons/star-off.svg" alt="stars" width={16} height={16} />
                  </div>
                </div>

                <div className="mt-6">
                  <button className="w-full border border-gray-200 rounded-lg py-3 text-sm text-gray-700 flex items-center justify-center gap-3 hover:bg-gray-50">
                    <Image src="/icons/messages.svg" width={20} height={20} className="text-gray-500" alt="msg" />
                    <span className="font-medium">Send a message</span>
                  </button>

                  <div className="mt-6 flex items-center justify-center gap-6 text-gray-400">
                    <Image src="/icons/x.svg" width={20} height={20} alt="tw" />
                    <Image src="/icons/instagram.svg" width={20} height={20} alt="ig" />
                    <Image src="/icons/linkedin.svg" width={20} height={20} alt="li" />
                    <Image src="/icons/fb.svg" width={20} height={20} alt="fb" />
                  </div>
                </div>
              </div>
            </aside>

            {/* Right content */}
            <section className="lg:col-span-9">
              {/* About box */}
              <div className="bg-white border border-gray-100 rounded-xl p-4 mb-6">
                <div className="text-sm font-semibold text-gray-700">About</div>
                <div className="text-sm text-gray-600 mt-2">Trusted real estate agent helping clients buy, sell, and rent properties with ease and transparency</div>
              </div>

              {/* Listings header */}
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-semibold">Listings</h3>
              </div>

              {/* Listings grid (profile) - uses client component for interactive features */}
              <ProfileListingsGrid sampleProperties={agentListings} />

              {/* Latest reviews */}
              <div className="mt-8">
                <div className="flex items-center justify-between mb-4">
                  <h4 className="text-lg font-semibold">Latest reviews</h4>
                  <div className="flex items-center gap-2">
                    <button className="w-8 h-8 rounded bg-white border flex items-center justify-center">◀</button>
