  const handleLandmarkAdd = () => {
    if (landmarkInput.trim()) {
      addLandmark(landmarkInput);
      setLandmarkInput('');
    }
  };

  const renderSelect = (label: string, fieldKey: string, value: string, options: string[]) => (
